def can_form_palindrome_after_removal(t, test_cases):
    results = []

    for n, k, s in test_cases:
        # Count frequency of each character
        freq = {}
        for char in s:
            if char in freq:
                freq[char] += 1
            else:
                freq[char] = 1

        # Count how many characters have an odd frequency
        odd_count = sum(1 for count in freq.values() if count % 2 != 0)

        # Remaining length after removing k characters
        remaining_length = n - k

        # Check palindrome conditions
        if remaining_length % 2 == 0:
            # If remaining length is even, we need odd_count <= k
            if odd_count <= k:
                results.append("YES")
            else:
                results.append("NO")
        else:
            # If remaining length is odd, we can have at most 1 odd count
            if odd_count <= k + 1:
                results.append("YES")
            else:
                results.append("NO")

    return results

