def min_operations_to_make_product_divisible(t, test_cases):
    results = []

    for n, k, a in test_cases:
        if k == 2:
            odd_count = sum(1 for x in a if x % 2 != 0)
            if odd_count == n:
                results.append(1)
            else:
                results.append(0)

        elif k == 3:
            not_div_by_3 = sum(1 for x in a if x % 3 != 0)
            if not_div_by_3 == 0:
                results.append(0)
            else:
                min_operations = float('inf')
                for x in a:
                    if x % 3 == 1:
                        min_operations = min(min_operations, 2)
                    elif x % 3 == 2:
                        min_operations = min(min_operations, 1)
                results.append(min_operations)

        elif k == 4:
            count_of_twos = sum(1 for x in a if x % 2 == 0)
            if count_of_twos >= 2:
                results.append(0)
            elif count_of_twos == 1:
                results.append(1)
            else:
                results.append(2)

        elif k == 5:
            not_div_by_5 = sum(1 for x in a if x % 5 != 0)
            if not_div_by_5 == 0:
                results.append(0)
            else:
                min_operations = float('inf')
                for x in a:
                    if x % 5 == 1:
                        min_operations = min(min_operations, 4)
                    elif x % 5 == 2:
                        min_operations = min(min_operations, 3)
                    elif x % 5 == 3:
                        min_operations = min(min_operations, 2)
                    elif x % 5 == 4:
                        min_operations = min(min_operations, 1)
                results.append(min_operations)

    return results

