def count_pairs(test_cases):
    results = []

    for a in test_cases:
        n = a[0]
        arr = a[1]

        # Frequency map to count occurrences of each exponent
        freq = {}
        for num in arr:
            if num in freq:
                freq[num] += 1
            else:
                freq[num] = 1

        # Count valid pairs
        count = 0

        # Count pairs from the same exponent
        for value in freq.values():
            if value > 1:
                count += (value * (value - 1)) // 2

        # Count pairs from different exponents
        keys = list(freq.keys())
        for i in range(len(keys)):
            for j in range(i + 1, len(keys)):
                a_i = keys[i]
                a_j = keys[j]
                if (a_i == 1 and a_j == 2) or (a_i == 2 and a_j == 1) or (a_i % a_j == 0 or a_j % a_i == 0):
                    count += freq[a_i] * freq[a_j]

        results.append(count)

    return results

