class Solution:
    def buyChoco(self, prices: List[int], money: int) -> int:
        n = len(prices)
        min_total_price = float('inf')  # Initialize to a large number

        # Generate all unique pairs of chocolate prices
        for i in range(n):
            for j in range(i + 1, n):
                total_price = prices[i] + prices[j]

                # Check if the total price is within the available money
                if total_price <= money:
                    min_total_price = min(min_total_price, total_price)

        # Calculate leftover money
        if min_total_price == float('inf'):
            return money  # No valid pairs found
        else:
            return money - min_total_price  # Return leftover money

class Solution:
    def count(self, num1: str, num2: str, min_sum: int, max_sum: int) -> int:
        MOD = 10**9 + 7

        def digit_sum(x):
            return sum(int(d) for d in str(x))

        def count_good_numbers(low, high):
            count = 0
            for x in range(low, high + 1):
                d_sum = digit_sum(x)
                if min_sum <= d_sum <= max_sum:
                    count += 1
                    count %= MOD
            return count

        low = int(num1)
        high = int(num2)

        return count_good_numbers(low, high)

