class Solution:
    def semiOrderedPermutation(self, nums: List[int]) -> int:
        n = len(nums)

        # Find the positions of 1 and n
        pos1 = nums.index(1)
        posN = nums.index(n)

        # If already semi-ordered
        if pos1 == 0 and posN == n - 1:
            return 0

        # Calculate moves
        if pos1 < posN:
            # No overlap
            return pos1 + (n - 1 - posN)
        else:
            # They will cross each other
            return pos1 + (n - 1 - posN) - 1

class Solution:
    def longestSemiRepetitiveSubstring(self, s: str) -> int:
        n = len(s)
        start = 0
        max_length = 0
        consecutive_pairs = 0

        for end in range(n):
            # Check for consecutive pairs
            if end > 0 and s[end] == s[end - 1]:
                consecutive_pairs += 1

            # If we have more than one consecutive pair, move the start pointer
            while consecutive_pairs > 1:
                if start < n - 1 and s[start] == s[start + 1]:
                    consecutive_pairs -= 1
                start += 1

            # Calculate the length of the current valid substring
            max_length = max(max_length, end - start + 1)

        return max_length

