class Solution:
    def minLength(self, s: str) -> int:
        stack = []

        for char in s:
            stack.append(char)
            # Check if the last two characters form "AB" or "CD"
            if len(stack) >= 2 and ((stack[-1] == 'B' and stack[-2] == 'A') or (stack[-1] == 'D' and stack[-2] == 'C')):
                stack.pop()  # Remove the last character
