class Solution:
    def punishmentNumber(self, n: int) -> int:
        def can_partition(s, target):
            if not s:  # Check if the string is empty
                return target == 0  # If target is also 0, it's a valid partition
            if target < 0:  # If the target goes negative, return False
                return False
            if s[0] == '0' and len(s) > 1:
                return False
            for i in range(1, len(s) + 1):
                num = int(s[:i])
                if num > target:
                    break
                if can_partition(s[i:], target - num):
                    return True
            return False

        total = 0
        for i in range(1, n + 1):
            square_str = str(i * i)
            if can_partition(square_str, i):
                total += i * i

        return total

class Solution:
    def minimumSum(self, n: int, k: int) -> int:
        result = []
        used = set()

        for i in range(1, n + 1):
            if (k - i) not in used:
                result.append(i)
                used.add(i)

        # If we have less than n elements, we need to add more distinct integers
        # starting from n + 1 until we reach the required length
        current = n + 1
        while len(result) < n:
            if (k - current) not in used:
                result.append(current)
                used.add(current)
            current += 1

        return sum(result)

