class Solution:
    def canTraverseAllPairs(self, nums: List[int]) -> bool:
        n = len(nums)

        # Step 1: Create a mapping of prime factors to indices
        prime_to_indices = defaultdict(list)

        # Function to find prime factors
        def prime_factors(x):
            factors = set()
            # Check for number of 2s that divide x
            while x % 2 == 0:
                factors.add(2)
                x //= 2
            # x must be odd at this point, so we can skip even numbers
            for i in range(3, int(x**0.5) + 1, 2):
                while x % i == 0:
                    factors.add(i)
                    x //= i
            if x > 2:
                factors.add(x)
            return factors

        # Step 2: Populate the prime_to_indices mapping
        for index, num in enumerate(nums):
            for prime in prime_factors(num):
                prime_to_indices[prime].append(index)

        # Step 3: Build the graph using the prime factor mapping
        graph = defaultdict(list)
        for indices in prime_to_indices.values():
            for i in range(len(indices)):
                for j in range(i + 1, len(indices)):
                    graph[indices[i]].append(indices[j])
                    graph[indices[j]].append(indices[i])

        # Step 4: Perform DFS to check connectivity
        visited = [False] * n

        def dfs(node):
            stack = [node]
            while stack:
                current = stack.pop()
                for neighbor in graph[current]:
                    if not visited[neighbor]:
                        visited[neighbor] = True
                        stack.append(neighbor)

        # Start DFS from the first index
        visited[0] = True
        dfs(0)

        # Step 5: Check if all indices are visited
        return all(visited)

