class Solution:
    def longestEqualSubarray(self, nums: List[int], k: int) -> int:
        unique_values = set(nums)
        max_length = 0

        for target in unique_values:
            left = 0
            count_non_target = 0

            for right in range(len(nums)):
                if nums[right] != target:
                    count_non_target += 1

                while count_non_target > k:
                    if nums[left] != target:
                        count_non_target -= 1
                    left += 1

                max_length = max(max_length, right - left - count_non_target + 1)

        return max_length

class Solution:
    def relocateMarbles(self, nums: List[int], moveFrom: List[int], moveTo: List[int]) -> List[int]:
        # Initialize a set to track unique occupied positions
        occupied_positions = set(nums)

        # Iterate through the moves
        for from_pos, to_pos in zip(moveFrom, moveTo):
            # Remove the position from which marbles are moved
            if from_pos in occupied_positions:
                occupied_positions.remove(from_pos)
            # Add the position to which marbles are moved
            occupied_positions.add(to_pos)

        # Return the sorted list of unique occupied positions
        return sorted(occupied_positions)

class Solution:
    def makeTheIntegerZero(self, num1: int, num2: int) -> int:
        # If num2 is greater than or equal to num1, we cannot reduce num1 to zero
        if num2 >= num1:
            return -1

        # Calculate the maximum possible value we can subtract
        max_subtract = [2**i + num2 for i in range(61)]

        # BFS setup
        from collections import deque

        queue = deque([(num1, 0)])  # (current value, number of operations)
        visited = set([num1])

        while queue:
            current, operations = queue.popleft()

            # Try all possible subtractions
            for value in max_subtract:
                next_value = current - value

                if next_value < 0:
                    continue  # We can't go below zero

                if next_value == 0:
                    return operations + 1  # Found a way to make num1 zero

                if next_value not in visited:
                    visited.add(next_value)
                    queue.append((next_value, operations + 1))

        return -1  # If we exhaust all options and never reach zero

