from functools import lru_cache

class Solution:
    def specialPerm(self, nums: List[int]) -> int:
        n = len(nums)
        MOD = 10**9 + 7

        # Create a graph of valid adjacency pairs
        valid_pairs = [[False] * n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                if i != j:
                    if nums[i] % nums[j] == 0 or nums[j] % nums[i] == 0:
                        valid_pairs[i][j] = True

        # Use backtracking with memoization to count special permutations
        @lru_cache(None)
        def backtrack(visited_mask, last_index):
            # If all numbers are used, we found a valid permutation
            if visited_mask == (1 << n) - 1:
                return 1

            count = 0
            for next_index in range(n):
                if not (visited_mask & (1 << next_index)) and valid_pairs[last_index][next_index]:
                    count += backtrack(visited_mask | (1 << next_index), next_index)
                    count %= MOD

            return count

        total_count = 0
        # Start from each number as the first element of the permutation
        for i in range(n):
            total_count += backtrack(1 << i, i)
            total_count %= MOD

        return total_count

class Solution:
    def sumImbalanceNumbers(self, nums: List[int]) -> int:
        n = len(nums)
        total_imbalance = 0

        # Generate all subarrays
        for start in range(n):
            for end in range(start, n):
                # Create the subarray
                subarray = nums[start:end + 1]
                # Sort the subarray
                sorted_subarray = sorted(subarray)

                # Calculate the imbalance number
                imbalance_count = 0
                for i in range(len(sorted_subarray) - 1):
                    if sorted_subarray[i + 1] - sorted_subarray[i] > 1:
                        imbalance_count += 1

                # Accumulate the total imbalance
                total_imbalance += imbalance_count

        return total_imbalance

class Solution:
    def distanceTraveled(self, mainTank: int, additionalTank: int) -> int:
        total_distance = 0

        # While there is fuel in the main tank
        while mainTank > 0:
            # Calculate how much fuel can be consumed in this cycle
            if mainTank >= 5:
                # If we can consume 5 liters
                total_distance += 50  # 5 liters * 10 km/liter
                mainTank -= 5  # Reduce main tank by 5 liters
                if additionalTank > 0:
                    # Transfer 1 liter from additional tank if available
                    additionalTank -= 1
                    mainTank += 1  # Add 1 liter back to main tank
            else:
                # If less than 5 liters remain, consume all of it
                total_distance += mainTank * 10  # Remaining liters * 10 km/liter
                mainTank = 0  # Main tank is now empty

        return total_distance

class Solution:
    def longestAlternatingSubarray(self, nums: List[int], threshold: int) -> int:
        max_length = 0

        for i in range(len(nums)):
            if nums[i] % 2 == 0 and nums[i] <= threshold:  # Check if the starting element is even and within threshold
                current_length = 1
                last_num = nums[i]

                for j in range(i + 1, len(nums)):
                    if (last_num % 2 != nums[j] % 2) and (nums[j] <= threshold):  # Check for alternating parity and threshold
                        current_length += 1
                        last_num = nums[j]
                    else:
                        break  # Break if the conditions are not met

                max_length = max(max_length, current_length)  # Update max_length if current is longer

        return max_length

class Solution:
    def continuousSubarrays(self, nums: List[int]) -> int:
        start = 0
        count = 0
        n = len(nums)

        for end in range(n):
            # Expand the window until it becomes invalid
            while max(nums[start:end + 1]) - min(nums[start:end + 1]) > 2:
                start += 1

            # All subarrays ending at 'end' and starting from 'start' to 'end' are valid
            count += (end - start + 1)

        return count

