class Solution:
    def maxArrayValue(self, nums: List[int]) -> int:
        current_sum = 0

        # Traverse the array from the end to the beginning
        for i in range(len(nums) - 1, -1, -1):
            # If current sum is greater than or equal to the current number,
            # we can add this number to the current sum
            if current_sum >= nums[i]:
                current_sum += nums[i]
            else:
                # Otherwise, we start a new sum with this number
                current_sum = nums[i]

        # The maximum value we can achieve is the current sum
        return current_sum

