from itertools import permutations

class Solution:
    def minimumString(self, a: str, b: str, c: str) -> str:

        def overlap(s1: str, s2: str) -> int:
            """Return the maximum overlap length where s1 suffix matches s2 prefix."""
            max_overlap = 0
            # Check for overlaps from length 1 to min(len(s1), len(s2))
            for i in range(1, min(len(s1), len(s2)) + 1):
                if s1[-i:] == s2[:i]:
                    max_overlap = i
            return max_overlap

        def combine(s1: str, s2: str) -> str:
            """Combine s1 and s2 with maximum overlap."""
            ov = overlap(s1, s2)
            return s1 + s2[ov:]

        min_length = float('inf')
        result = ""

        # Generate all permutations of the strings
        for perm in permutations([a, b, c]):
            # Combine the three strings in the order of the permutation
            combined = combine(perm[0], perm[1])
            combined = combine(combined, perm[2])

            # Check the length and lexicographical order
            if len(combined) < min_length:
                min_length = len(combined)
                result = combined
            elif len(combined) == min_length:
                result = min(result, combined)

        return result

