class Solution:
    def checkArray(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        current_decrement = 0
        decrement_effect = [0] * n

        for i in range(n):
            if i > 0:
                current_decrement += decrement_effect[i]  # Apply the effect from previous elements

            if current_decrement > nums[i]:
                return False

            needed_decrement = nums[i] - current_decrement

            if needed_decrement > 0:
                current_decrement += needed_decrement
                if i + k < n:
                    decrement_effect[i + k] -= needed_decrement  # Mark the end of the effect

        return True

class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        n = len(s)

        # Precompute the cost to convert each substring s[l:r+1] into a semi-palindrome
        cost = [[float('inf')] * n for _ in range(n)]

        for l in range(n):
            for r in range(l, n):
                length = r - l + 1
                # Check all divisors d of length
                for d in range(1, length):
                    if length % d == 0:
                        # Count frequency of characters in each group
                        changes = 0
                        for i in range(d):
                            freq = [0] * 26
                            for j in range(i, length, d):
                                freq[ord(s[l + j]) - ord('a')] += 1

                            # Count how many characters need to be changed to make this group a palindrome
                            odd_count = sum(1 for count in freq if count % 2 != 0)
                            changes += odd_count // 2  # Each pair of odd counts can be made even with one change

                        cost[l][r] = min(cost[l][r], changes)

        # Initialize DP table
        dp = [[float('inf')] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0  # No changes needed for empty substring

        # Fill the DP table
        for j in range(1, k + 1):
            for i in range(1, n + 1):
                for l in range(i):
                    if dp[l][j - 1] != float('inf'):  # Only consider valid previous states
                        dp[i][j] = min(dp[i][j], dp[l][j - 1] + cost[l][i - 1])

        return dp[n][k]

