class Solution:
    def countInterestingSubarrays(self, nums: List[int], modulo: int, k: int) -> int:
        count = 0
        current_count = 0
        prefix_count = {0: 1}  # To handle the case when cnt % modulo == k directly

        for num in nums:
            # Check if the current number satisfies the modulo condition
            if num % modulo == k:
                current_count += 1

            # We need to check if (current_count - k) % modulo is in prefix_count
            # This means we are looking for how many times we have seen this count before
            target_count = (current_count - k) % modulo

            # If target_count is in prefix_count, it means we found some subarrays
            if target_count in prefix_count:
                count += prefix_count[target_count]

            # Update the prefix_count for the current_count
            if current_count % modulo in prefix_count:
                prefix_count[current_count % modulo] += 1
            else:
                prefix_count[current_count % modulo] = 1

        return count

class Solution:
    def canSplitArray(self, nums: List[int], m: int) -> bool:
        n = len(nums)

        # If there's only one element, we can only return true if it's less than m
        if n == 1:
            return nums[0] >= m

        # Function to check if we can split the array into valid subarrays
        def can_split(start, end):
            # If the length of the current subarray is 1, it's already valid
            if end - start == 1:
                return True

            # Calculate the sum of the current subarray
            total_sum = sum(nums[start:end])

            # If the total sum is less than m, we cannot split it into valid parts
            if total_sum < m:
                return False

            # Try to split the array at every possible position
            for split_point in range(start + 1, end):
                left_sum = sum(nums[start:split_point])
                right_sum = total_sum - left_sum

                # Check if either side can be a valid subarray
                if (split_point - start == 1 or left_sum >= m) and (end - split_point == 1 or right_sum >= m):
                    if can_split(start, split_point) and can_split(split_point, end):
                        return True

            return False

        # Start checking from the whole array
        return can_split(0, n)

