class Solution:
    def countSteppingNumbers(self, low: str, high: str) -> int:
        MOD = 10**9 + 7

        def bfs(start):
            queue = [start]
            count = 0

            while queue:
                num = queue.pop(0)
                if len(num) > len(high) or (len(num) == len(high) and num > high):
                    continue
                if len(num) > len(low) or (len(num) == len(low) and num >= low):
                    count = (count + 1) % MOD

                last_digit = int(num[-1])
                if last_digit > 0:
                    queue.append(num + str(last_digit - 1))
                if last_digit < 9:
                    queue.append(num + str(last_digit + 1))

            return count

        total_count = 0

        for i in range(1, 10):  # Start from 1 to 9 to avoid leading zeros
            total_count = (total_count + bfs(str(i))) % MOD

        return total_count

