class Solution:
    def minAbsoluteDifference(self, nums: List[int], x: int) -> int:
        n = len(nums)

        # Handle edge cases
        if n < 2:
            return -1  # Not enough elements to compare
        if x == 0:
            return 0  # Same element can be selected, difference is 0

        # Create a list of tuples (value, index)
        indexed_nums = [(nums[i], i) for i in range(n)]
        # Sort the list based on the values
        indexed_nums.sort()

        min_diff = float('inf')

        # Iterate through the sorted list
        for i in range(n):
            for j in range(i + 1, n):
                # Check if the indices are at least x apart
                if abs(indexed_nums[i][1] - indexed_nums[j][1]) >= x:
                    # Calculate the absolute difference
                    diff = abs(indexed_nums[i][0] - indexed_nums[j][0])
                    # Update the minimum difference
                    min_diff = min(min_diff, diff)
                # Since the array is sorted, if the index difference is already too small, break
                if abs(indexed_nums[i][1] - indexed_nums[j][1]) < x:
                    continue

        return min_diff

