        if len(str2) > len(str1):
            return False

        i, j = 0, 0

        while i < len(str1) and j < len(str2):
            if str1[i] == str2[j]:
                i += 1
                j += 1
            elif str1[i] < str2[j]:
                i += 1
            else:
                next_char = chr((ord(str1[i]) - ord('a') + 1) % 26 + ord('a'))
                if next_char == str2[j]:  # Only allow one increment
                    i += 1
                    j += 1
                else:
                    i += 1

        return j == len(str2)

