        MOD = 10**9 + 7
        n = len(s)

        if s == t:
            return n % MOD

        k = k % n

        transformations = set()

        for i in range(n):
            transformed = s[i:] + s[:i]
            transformations.add(transformed)

        count = 0
        for trans in transformations:
            if (trans[-k:] + trans[:-k]) == t:
                count = (count + 1) % MOD

        return count

