class Solution:
    def constructProductMatrix(self, grid: List[List[int]]) -> List[List[int]]:
        n = len(grid)
        m = len(grid[0])

        total_product = 1
        zero_count = 0
        non_zero_product = 1

        # Calculate total product and count zeros
        for i in range(n):
            for j in range(m):
                if grid[i][j] == 0:
                    zero_count += 1
                else:
                    total_product = (total_product * grid[i][j]) % 12345
                    non_zero_product = (non_zero_product * grid[i][j]) % 12345

        # Initialize the product matrix
        p = [[0] * m for _ in range(n)]

        if zero_count > 1:
            return p
        elif zero_count == 1:
            for i in range(n):
                for j in range(m):
                    if grid[i][j] == 0:
                        p[i][j] = non_zero_product
                    else:
                        p[i][j] = 0
            return p
        else:
            for i in range(n):
                for j in range(m):
                    p[i][j] = (total_product * pow(grid[i][j], 12345 - 2, 12345)) % 12345

            return p

