    def numberOfPoints(self, nums: List[List[int]]) -> int:
        # Step 1: Initialize a list to store merged segments
        merged_segments = []

        # Step 2: Sort the car segments based on their starting points
        nums.sort(key=lambda x: x[0])

        # Step 3: Iterate through the sorted segments
        for start, end in nums:
            if not merged_segments or merged_segments[-1][1] < start:
                # No overlap, add the current segment
                merged_segments.append([start, end])
            else:
                # Overlap, merge the segments
                merged_segments[-1][1] = max(merged_segments[-1][1], end)

        # Step 4: Count the total unique integer points
        total_points = 0
        for start, end in merged_segments:
            total_points += (end - start + 1)  # Include both endpoints

        # Step 5: Return the total count
        return total_points

