class Solution:
    def minimumRightShifts(self, nums: List[int]) -> int:
        n = len(nums)
        break_points = 0
        break_index = -1

        # Count the number of break points
        for i in range(n):
            if nums[i] > nums[(i + 1) % n]:
                break_points += 1
                break_index = i

        # If there are more than one break points, sorting is not possible
        if break_points > 1:
            return -1

        # If there are no break points, the array is already sorted
        if break_points == 0:
            return 0

        # If there is exactly one break point, calculate the number of shifts
        return n - (break_index + 1)

