class Solution:
    def maximumSum(self, nums: List[int]) -> int:
        def prime_factors(n):
            factors = defaultdict(int)
            while n % 2 == 0:
                factors[2] += 1
                n //= 2
            for i in range(3, isqrt(n) + 1, 2):
                while n % i == 0:
                    factors[i] += 1
                    n //= i
            if n > 2:
                factors[n] += 1
            return factors

        parity_map = defaultdict(int)

        for num in nums:
            factors = prime_factors(num)
            parity_signature = tuple((p, exp % 2) for p, exp in sorted(factors.items()))
            parity_map[parity_signature] += num

        return max(parity_map.values(), default=0)

