class Solution:
    def countSubMultisets(self, nums: List[int], l: int, r: int) -> int:
        from collections import Counter

        MOD = 10**9 + 7

        # Count the frequency of each unique number in nums
        freq = Counter(nums)

        # Initialize the DP array
        max_sum = sum(num * count for num, count in freq.items())
        dp = [0] * (max_sum + 1)
        dp[0] = 1  # There's one way to make the sum 0 (the empty set)

        # Process each unique number and its count
        for num, count in freq.items():
            # Update the DP array for the current number
            for j in range(max_sum, num - 1, -1):
                for k in range(1, count + 1):
                    if j >= num * k:
                        dp[j] = (dp[j] + dp[j - num * k]) % MOD
                    else:
                        break

        # Count the valid sums in the range [l, r]
        result = sum(dp[l:r + 1]) % MOD

        return result

