        # Initialize the dp array
        dp = [-1] * (target + 1)
        dp[0] = 0  # Base case: sum of 0 can be achieved with an empty subsequence

        # Iterate through each number in nums
        for num in nums:
            # Update the dp array in reverse order
            for j in range(target, num - 1, -1):
                if dp[j - num] != -1:  # If the previous sum can be achieved
                    dp[j] = max(dp[j], dp[j - num] + 1)  # Update the length of the subsequence

