        n = len(nums)
        # Create a prefix sum array
        prefix_sum = [0] * (2 * n + 1)

        # Fill the prefix sum array for the first two cycles of nums
        for i in range(2 * n):
            prefix_sum[i + 1] = prefix_sum[i] + nums[i % n]

        min_length = float('inf')
        start = 0

        # Use two pointers to find the minimum length subarray
        for end in range(2 * n + 1):
            while start < end and prefix_sum[end] - prefix_sum[start] > target:
                start += 1
            if start < end and prefix_sum[end] - prefix_sum[start] == target:
