    def shortestBeautifulSubstring(self, s: str, k: int) -> str:
        n = len(s)
        count_ones = s.count('1')

        # If there are not enough '1's in the string, return empty string
        if count_ones < k:
            return ""

        min_length = float('inf')
        result = ""

        start = 0
        current_count = 0

        for end in range(n):
            # Expand the window by including s[end]
            if s[end] == '1':
                current_count += 1

            # When we have exactly k '1's, check the substring
            while current_count >= k:
                if current_count == k:
                    current_length = end - start + 1
                    current_substring = s[start:end + 1]

                    # Update the result if we found a smaller length or a lexicographically smaller substring
                    if current_length < min_length:
                        min_length = current_length
                        result = current_substring
                    elif current_length == min_length:
                        result = min(result, current_substring)

                # Move the start pointer to reduce the window size
                if s[start] == '1':
                    current_count -= 1
                start += 1

        return result

