import heapq

class Solution:
    def minProcessingTime(self, processorTime: List[int], tasks: List[int]) -> int:
        if not tasks:
            return max(processorTime)

        processorTime.sort()
        tasks.sort(reverse=True)

        completion_times = [(time, i) for i, time in enumerate(processorTime)]
        heapq.heapify(completion_times)
        task_count = [0] * len(processorTime)

        while tasks:
            earliest_free_time, processor_index = heapq.heappop(completion_times)
            if task_count[processor_index] < 4:
                task = tasks.pop(0)
                new_completion_time = earliest_free_time + task
                task_count[processor_index] += 1
                heapq.heappush(completion_times, (new_completion_time, processor_index))
            else:
                heapq.heappush(completion_times, (earliest_free_time, processor_index))

        return max(completion_times)[0]

