class Solution:
    def distributeCandies(self, n: int, limit: int) -> int:
        # Check feasibility
        if n > 3 * limit:
            return 0

        # Initialize a DP table
        dp = [[0] * (n + 1) for _ in range(4)]
        dp[0][0] = 1  # Base case: 1 way to distribute 0 candies to 0 children

        # Iterate over each child
        for child in range(1, 4):
            for candies in range(n + 1):
                # Calculate the number of ways to distribute candies to this child
                for k in range(min(candies, limit) + 1):
                    dp[child][candies] += dp[child - 1][candies - k]

        return dp[3][n]

