class Solution:
    def numberOfGoodPartitions(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)

        dp = [0] * (n + 1)
        dp[0] = 1  # There's one way to partition an empty array

        last_occurrence = {}

        for i in range(1, n + 1):
            num = nums[i - 1]
            dp[i] = (dp[i - 1] * 2) % MOD

            if num in last_occurrence:
                last_index = last_occurrence[num]
                dp[i] = (dp[i] - dp[last_index - 1] + MOD) % MOD

            last_occurrence[num] = i

