class Solution:
    def lexicographicallySmallestArray(self, nums: List[int], limit: int) -> List[int]:
        from collections import defaultdict

        n = len(nums)
        parent = list(range(n))

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            rootX = find(x)
            rootY = find(y)
            if rootX != rootY:
                parent[rootY] = rootX

        # Create groups based on the limit condition
        for i in range(n):
            for j in range(i + 1, n):
                if abs(nums[i] - nums[j]) <= limit:
                    union(i, j)

        # Group indices by their root parent
        groups = defaultdict(list)
        for i in range(n):
            root = find(i)
            groups[root].append(i)

        # Create the result array
        result = [0] * n

        # Sort each group and place back in the result
        for indices in groups.values():
            # Extract the values for the current group
            values = [nums[i] for i in indices]
            # Sort the values
            values.sort()
            # Place sorted values back into the result array
            for idx, value in zip(sorted(indices), values):
                result[idx] = value

        return result

