class Solution:
    def maxPartitionsAfterOperations(self, s: str, k: int) -> int:
        def calculate_partitions(s: str, k: int) -> int:
            n = len(s)
            left = 0
            right = 0
            char_count = {}
            partitions = 0

            while right < n:
                char_count[s[right]] = char_count.get(s[right], 0) + 1

                while len(char_count) > k:
                    char_count[s[left]] -= 1
                    if char_count[s[left]] == 0:
                        del char_count[s[left]]
                    left += 1

                if len(char_count) <= k:
                    partitions += 1

                right += 1

            return partitions

        max_partitions = calculate_partitions(s, k)

        for i in range(len(s)):
            original_char = s[i]
            for new_char in set('abcdefghijklmnopqrstuvwxyz') - {original_char}:
                modified_s = s[:i] + new_char + s[i+1:]
                max_partitions = max(max_partitions, calculate_partitions(modified_s, k))

        return max_partitions

