class Solution:
    def minimumCost(self, source: str, target: str, original: List[str], changed: List[str], cost: List[int]) -> int:
        # Step 1: Build a mapping of transformations
        transformation_map = defaultdict(list)
        for orig, chng, cst in zip(original, changed, cost):
            transformation_map[orig].append((chng, cst))

        total_cost = 0

        # Function to perform BFS to find minimum cost
        def bfs_min_cost(start, target):
            queue = deque([(start, 0)])  # (current character, current cost)
            visited = set()
            min_cost = float('inf')

            while queue:
                current_char, current_cost = queue.popleft()
                if current_char == target:
                    min_cost = min(min_cost, current_cost)
                    continue
                if current_char in visited:
                    continue
                visited.add(current_char)

                for chng, cst in transformation_map[current_char]:
                    queue.append((chng, current_cost + cst))

            return min_cost if min_cost != float('inf') else -1

        # Step 2: Iterate through the source and target strings
        for s_char, t_char in zip(source, target):
            if s_char == t_char:
                continue  # No cost if characters are the same

            if s_char not in transformation_map:
                return -1  # Impossible to transform

            # Step 3: Calculate minimum cost for the transformation
            min_cost = bfs_min_cost(s_char, t_char)

            if min_cost == -1:
                return -1  # No valid transformation found

            total_cost += min_cost

        # Step 4: Return the total cost
        return total_cost

