class Solution:
    def minOperations(self, nums: List[int], k: int) -> int:
        current_xor = 0
        for num in nums:
            current_xor ^= num

        if current_xor == k:
            return 0

        required_xor = current_xor ^ k
        bit_flips_needed = 0

        for i in range(21):
            if (required_xor >> i) & 1:
                count_zeros = sum((num >> i) & 1 == 0 for num in nums)
                if count_zeros < len(nums):
                    bit_flips_needed += 1

        return bit_flips_needed

