class Solution:
    def canSortArray(self, nums: List[int]) -> bool:
        from collections import defaultdict

        # Step 1: Count set bits and group indices by set bit count
        def count_set_bits(x):
            return bin(x).count('1')

        groups = defaultdict(list)

        for index, num in enumerate(nums):
            set_bits_count = count_set_bits(num)
            groups[set_bits_count].append(index)

        # Step 2: Sort each group and reconstruct the array
        sorted_nums = sorted(nums)
        reconstructed = nums[:]

        for indices in groups.values():
            # Extract the elements corresponding to the current group
            elements = [nums[i] for i in indices]
            # Sort the elements
            elements.sort()
            # Place them back in the original indices
            for i, index in enumerate(sorted(indices)):
                reconstructed[index] = elements[i]

        # Step 3: Compare the reconstructed array with the sorted array
        return reconstructed == sorted_nums

