    if takahashi_wins > aoki_wins:
        return 'T'
    elif aoki_wins > takahashi_wins:
        return 'A'
    else:
        # If they have the same number of wins, determine who reached it first
        takahashi_count = 0
        aoki_count = 0
        max_wins = takahashi_wins  # or aoki_wins, since they are equal

        for char in S:
            if char == 'T':
                takahashi_count += 1
            elif char == 'A':
                aoki_count += 1

            if takahashi_count == max_wins:
                return 'T'
            if aoki_count == max_wins:
                return 'A'

