from collections import deque
import sys
import itertools

def bfs(start, grid, H, W):
    dist = [[float('inf')] * W for _ in range(H)]
    queue = deque([start])
    dist[start[0]][start[1]] = 0

    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    while queue:
        x, y = queue.popleft()
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < H and 0 <= ny < W and grid[nx][ny] != '#':
                if dist[nx][ny] == float('inf'):
                    dist[nx][ny] = dist[x][y] + 1
                    queue.append((nx, ny))

    return dist

def solve():
    input = sys.stdin.read
    data = input().splitlines()

    H, W, T = map(int, data[0].split())
    grid = [list(data[i + 1]) for i in range(H)]

    start = goal = None
    candies = []

    for i in range(H):
        for j in range(W):
            if grid[i][j] == 'S':
                start = (i, j)
            elif grid[i][j] == 'G':
                goal = (i, j)
            elif grid[i][j] == 'o':
                candies.append((i, j))

    # BFS from start and goal
    dist_from_start = bfs(start, grid, H, W)
    dist_from_goal = bfs(goal, grid, H, W)

    # Check if goal is reachable from start
    min_dist_to_goal = dist_from_start[goal[0]][goal[1]]
    if min_dist_to_goal > T:
        print(-1)
        return

    max_candies = 0
    num_candies = len(candies)

    # Precompute distances between all candies
    candy_distances = [[0] * num_candies for _ in range(num_candies)]
    for i in range(num_candies):
        for j in range(num_candies):
            if i != j:
                candy_distances[i][j] = bfs(candies[i], grid, H, W)[candies[j][0]][candies[j][1]]

    # Check all subsets of candies
    for mask in range(1 << num_candies):
        total_moves = 0
        last_pos = start
        last_candy_index = -1

        for i in range(num_candies):
            if mask & (1 << i):
                candy_pos = candies[i]
                if last_candy_index == -1:
                    total_moves += dist_from_start[candy_pos[0]][candy_pos[1]]
                else:
                    total_moves += candy_distances[last_candy_index][i]
                last_candy_index = i

        if last_candy_index != -1:
            total_moves += dist_from_goal[candies[last_candy_index][0]][candies[last_candy_index][1]]

        if total_moves <= T:
            max_candies = max(max_candies, bin(mask).count('1'))

    print(max_candies)

