class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n + 1))
        self.rank = [1] * (n + 1)

    def find(self, u):
        if self.parent[u] != u:
            self.parent[u] = self.find(self.parent[u])  # Path compression
        return self.parent[u]

    def union(self, u, v):
        root_u = self.find(u)
        root_v = self.find(v)
        if root_u != root_v:
            if self.rank[root_u] > self.rank[root_v]:
                self.parent[root_v] = root_u
            elif self.rank[root_u] < self.rank[root_v]:
                self.parent[root_u] = root_v
            else:
                self.parent[root_v] = root_u
                self.rank[root_u] += 1

def is_good_graph(n, edges, forbidden_pairs, queries):
    uf = UnionFind(n)

    for u, v in edges:
        uf.union(u, v)

    results = []
    for p, q in queries:
        uf.union(p, q)
        is_good = True
        for x, y in forbidden_pairs:
            if uf.find(x) == uf.find(y):
                is_good = False
                break
        results.append("Yes" if is_good else "No")
        uf = UnionFind(n)
        for u, v in edges:
            uf.union(u, v)

    return results

