                if j + 1 < min_col:
                    min_col = j + 1  # +1 for 1-based index
                if j + 1 > max_col:
                    max_col = j + 1  # +1 for 1-based index

    # Now search for the empty square within the identified rectangle
    for i in range(min_row - 1, max_row):  # Convert back to 0-based index
        for j in range(min_col - 1, max_col):  # Convert back to 0-based index
            if grid[i][j] == '.':
                return (i + 1, j + 1)  # Return as 1-based index

