def can_create_sheet(H_A, W_A, A, H_B, W_B, B, H_X, W_X, X):
    # Collect all black squares from A and B
    black_squares_A = [(i, j) for i in range(H_A) for j in range(W_A) if A[i][j] == '#']
    black_squares_B = [(i, j) for i in range(H_B) for j in range(W_B) if B[i][j] == '#']

    # Total black squares needed in the cut-out
    total_black_squares = set(black_squares_A + black_squares_B)

    # Try all possible positions to paste A and B
    for a_row in range(-H_A + 1, H_X):
        for a_col in range(-W_A + 1, W_X):
            for b_row in range(-H_B + 1, H_X):
                for b_col in range(-W_B + 1, W_X):
                    # Create a temporary sheet C
                    C = [['.' for _ in range(W_X)] for _ in range(H_X)]

                    # Paste A onto C
                    for i in range(H_A):
                        for j in range(W_A):
                            if 0 <= a_row + i < H_X and 0 <= a_col + j < W_X and A[i][j] == '#':
                                C[a_row + i][a_col + j] = '#'

                    # Paste B onto C
                    for i in range(H_B):
                        for j in range(W_B):
                            if 0 <= b_row + i < H_X and 0 <= b_col + j < W_X and B[i][j] == '#':
                                C[b_row + i][b_col + j] = '#'

                    # Now check all possible cut-out positions
                    for cut_row in range(H_X - H_X + 1):
                        for cut_col in range(W_X - W_X + 1):
                            # Extract the cut-out area
                            cut_out = set()
                            for i in range(H_X):
                                for j in range(W_X):
                                    if C[cut_row + i][cut_col + j] == '#':
                                        cut_out.add((i, j))

                            # Check if the cut-out matches X and includes all black squares
                            matches = True
                            for i in range(H_X):
                                for j in range(W_X):
                                    if cut_row + i >= H_X or cut_col + j >= W_X or X[i][j] != C[cut_row + i][cut_col + j]:
                                        matches = False
                                        break
                                if not matches:
                                    break
                            if total_black_squares.issubset(cut_out) and matches:
                                return "Yes"

    return "No"

