def count_partitions(N, T, M, incompatible_pairs):
    from itertools import combinations

    # Create a graph to represent incompatibilities
    incompatibility_graph = [[] for _ in range(N + 1)]
    for a, b in incompatible_pairs:
        incompatibility_graph[a].append(b)
        incompatibility_graph[b].append(a)

    # Check if it's possible to partition
    if T > N:
        return 0
    if T == 1:
        return 0 if M > 0 else 1

    # Function to check if a current partition is valid
    def is_valid_partition(partition):
        for team in partition:
            for i in range(len(team)):
                for j in range(i + 1, len(team)):
                    if team[j] in incompatibility_graph[team[i]]:
                        return False
        return True

    # Generate all possible partitions of N players into T teams
    def generate_partitions(n, t):
        if t == 1:
            yield [list(range(1, n + 1))]
            return
        for first_team_size in range(1, n - t + 2):
            for first_team in combinations(range(1, n + 1), first_team_size):
                remaining_players = set(range(1, n + 1)) - set(first_team)
                for rest in generate_partitions(len(remaining_players), t - 1):
                    yield [list(first_team)] + rest

    valid_count = 0
    for partition in generate_partitions(N, T):
        if is_valid_partition(partition):
            valid_count += 1

    return valid_count

