    target_sum = 10

    total_outcomes = 1
    for a in A:
        total_outcomes = (total_outcomes * a) % MOD

    dp = [0] * (target_sum + 1)
    dp[0] = 1

    for a in A:
        for j in range(target_sum, 0, -1):
            for k in range(1, min(a, j) + 1):
                dp[j] = (dp[j] + dp[j - k]) % MOD

