def count_valid_parentheses(S):
    MOD = 998244353
    n = len(S)

    # dp[i][j] will store the number of ways to form valid parentheses
    # using the first i characters with a balance of j
    dp = [[0] * (n + 1) for _ in range(n + 1)]

    # Base case: 1 way to have an empty string with balance 0
    dp[0][0] = 1

    for i in range(n):
        for j in range(n + 1):
            if dp[i][j] == 0:
                continue

            if S[i] == '(':
                if j + 1 <= n:
                    dp[i + 1][j + 1] = (dp[i + 1][j + 1] + dp[i][j]) % MOD
            elif S[i] == ')':
                if j - 1 >= 0:
                    dp[i + 1][j - 1] = (dp[i + 1][j - 1] + dp[i][j]) % MOD
            elif S[i] == '?':
                # Treat as '('
                if j + 1 <= n:
                    dp[i + 1][j + 1] = (dp[i + 1][j + 1] + dp[i][j]) % MOD
                # Treat as ')'
                if j - 1 >= 0:
                    dp[i + 1][j - 1] = (dp[i + 1][j - 1] + dp[i][j]) % MOD

    # The answer is the number of ways to have a balance of 0 after processing all characters
    return dp[n][0]

