def count_face_sharing_cuboids(N, cuboids):
    # Prepare a list to store the counts of face-sharing cuboids
    face_sharing_counts = [0] * N

    # Create a list of cuboids with their indices
    indexed_cuboids = [(cuboids[i], i) for i in range(N)]

    # Function to check if two cuboids share a face
    def share_face(c1, c2):
        (x1_min, y1_min, z1_min, x1_max, y1_max, z1_max) = c1
        (x2_min, y2_min, z2_min, x2_max, y2_max, z2_max) = c2

        # Check for face sharing along the X-axis
        if x1_max == x2_min or x1_min == x2_max:
            if (y1_min < y2_max and y1_max > y2_min) and (z1_min < z2_max and z1_max > z2_min):
                return True

        # Check for face sharing along the Y-axis
        if y1_max == y2_min or y1_min == y2_max:
            if (x1_min < x2_max and x1_max > x2_min) and (z1_min < z2_max and z1_max > z2_min):
                return True

        # Check for face sharing along the Z-axis
        if z1_max == z2_min or z1_min == z2_max:
            if (x1_min < x2_max and x1_max > x2_min) and (y1_min < y2_max and y1_max > y2_min):
                return True

        return False

    # Check face sharing for each cuboid
    for i in range(N):
        for j in range(i + 1, N):
            if share_face(indexed_cuboids[i][0], indexed_cuboids[j][0]):
                face_sharing_counts[indexed_cuboids[i][1]] += 1
                face_sharing_counts[indexed_cuboids[j][1]] += 1

    return face_sharing_counts

