def remaining_cookies(H, W, grid):
    while True:
        marked = [[False] * W for _ in range(H)]
        marked_any = False

        # Mark rows
        for i in range(H):
            count = {}
            for j in range(W):
                if grid[i][j] not in count:
                    count[grid[i][j]] = 0
                count[grid[i][j]] += 1

            for j in range(W):
                if count[grid[i][j]] >= 2:
                    marked[i][j] = True
                    marked_any = True

        # Mark columns
        for j in range(W):
            count = {}
            for i in range(H):
                if grid[i][j] not in count:
                    count[grid[i][j]] = 0
                count[grid[i][j]] += 1

            for i in range(H):
                if count[grid[i][j]] >= 2:
                    marked[i][j] = True
                    marked_any = True

        # Remove marked cookies
        if not marked_any:
            break

        new_grid = []
        for i in range(H):
            new_row = []
            for j in range(W):
                if not marked[i][j]:
                    new_row.append(grid[i][j])
            if new_row:
                new_grid.append(new_row)

        # Update grid for the next iteration
        grid = new_grid
        H = len(grid)
        W = len(grid[0]) if H > 0 else 0

    # Count remaining cookies
    remaining_count = sum(len(row) for row in grid)
    return remaining_count

