def main():
    import sys
    from collections import defaultdict, deque

    input = sys.stdin.read
    data = input().splitlines()

    N = int(data[0])
    prerequisites = defaultdict(list)

    for i in range(1, N + 1):
        line = list(map(int, data[i].split()))
        C_i = line[0]
        if C_i > 0:
            prerequisites[i] = line[1:C_i + 1]

    to_read = set()
    visited = set()

    stack = [1]

    while stack:
        book = stack.pop()
        if book in visited:
            continue
        visited.add(book)
        for prereq in prerequisites[book]:
            if prereq not in visited:
                stack.append(prereq)
                to_read.add(prereq)

    indegree = {i: 0 for i in range(1, N + 1)}
    for book in range(1, N + 1):
        for prereq in prerequisites[book]:
            indegree[prereq] += 1

    queue = deque()
    for book in range(1, N + 1):
        if indegree[book] == 0 and book in to_read:
            queue.append(book)

    order = []

    while queue:
        book = queue.popleft()
        order.append(book)
        for prereq in prerequisites[book]:
            indegree[prereq] -= 1
            if indegree[prereq] == 0 and prereq in to_read:
                queue.append(prereq)

    order.reverse()
    result = [str(book) for book in order if book != 1]
    print(" ".join(result))

if __name__ == "__main__":
    main()

def max_weight_matching(N, weights):
    edges = []
    index = 0
    for i in range(1, N):
        for j in range(i + 1, N + 1):
            edges.append((weights[index], i, j))
            index += 1

    dp = [0] * (1 << N)

    for weight, u, v in edges:
        for mask in range((1 << N) - 1, -1, -1):
            if (mask & (1 << (u - 1))) == 0 and (mask & (1 << (v - 1))) == 0:
                new_mask = mask | (1 << (u - 1)) | (1 << (v - 1))
                dp[new_mask] = max(dp[new_mask], dp[mask] + weight)

    return max(dp)

