from collections import Counter

def is_disappointing(arrangement):
    # Check rows
    for i in range(3):
        for j in range(2):  # Check pairs (0,1) and (1,2)
            if j < 2 and arrangement[i][j] == arrangement[i][j+1] != arrangement[i][j+2]:
                return True

    # Check columns
    for j in range(3):
        for i in range(2):  # Check pairs (0,1) and (1,2)
            if i < 2 and arrangement[i][j] == arrangement[i+1][j] != arrangement[i+2][j]:
                return True

    # Check diagonals
    if arrangement[0][0] == arrangement[1][1] != arrangement[2][2]:
        return True
    if arrangement[2][0] == arrangement[1][1] != arrangement[0][2]:
        return True

    return False

def main():
    # Read input
    grid = [list(map(int, input().split())) for _ in range(3)]
    numbers = [grid[i][j] for i in range(3) for j in range(3)]

    # Total arrangements
    total_arrangements = math.factorial(9) // math.prod([math.factorial(v) for v in Counter(numbers).values()])

    # Count valid arrangements
    valid_count = 0

    # Generate all unique permutations of the numbers
    for perm in itertools.permutations(numbers):
        arrangement = [list(perm[i:i+3]) for i in range(0, 9, 3)]
        if not is_disappointing(arrangement):
            valid_count += 1

    # Calculate the probability
    probability = valid_count / total_arrangements

    # Print the result with sufficient precision
    print(f"{probability:.30f}")

