def can_fill_grid(polyominoes):
    # Create a 4x4 grid to represent the filled state
    grid = [[False] * 4 for _ in range(4)]

    # Function to check if a polyomino can be placed at a specific position
    def can_place(polyomino, row, col):
        for r, c in polyomino:
            if not (0 <= row + r < 4 and 0 <= col + c < 4) or grid[row + r][col + c]:
                return False
        return True

    # Function to place a polyomino on the grid
    def place(polyomino, row, col):
        for r, c in polyomino:
            grid[row + r][col + c] = True

    # Function to remove a polyomino from the grid
    def remove(polyomino, row, col):
        for r, c in polyomino:
            grid[row + r][col + c] = False

    # Backtracking function to try placing all polyominoes
    def backtrack(index):
        if index == len(polyominoes):
            return all(all(row) for row in grid)  # Check if the grid is fully filled

        for polyomino in polyominoes[index]:
            for row in range(4):
                for col in range(4):
                    if can_place(polyomino, row, col):
                        place(polyomino, row, col)
                        if backtrack(index + 1):
                            return True
                        remove(polyomino, row, col)
        return False

    return backtrack(0)

def rotate(polyomino):
    return [(c, -r) for r, c in polyomino]

def get_polyomino_shapes(input_data):
