def generate_all_rotations(polyomino):
    rotations = []
    current = polyomino
    for _ in range(4):
        min_row = min(r for r, c in current)
        min_col = min(c for r, c in current)
        normalized = [(r - min_row, c - min_col) for r, c in current]
        rotations.append(normalized)
        current = rotate(current)
    return rotations

