def can_be_expressed_as_2x3y(N):
    # Factor out 2
    while N % 2 == 0:
        N //= 2

    # Factor out 3
    while N % 3 == 0:
        N //= 3

    # If N is reduced to 1, it means it was only composed of 2s and 3s
    return N == 1

