def possible_original_strings(N, T_prime, strings):
    result_indices = []

    len_T_prime = len(T_prime)

    for i in range(N):
        S = strings[i]
        len_S = len(S)

        # Check for exact match
        if S == T_prime:
            result_indices.append(i + 1)
            continue

        # Check for insertion (S should be one character shorter than T')
        if len_S + 1 == len_T_prime:
            for j in range(len_T_prime):
                if T_prime[:j] + T_prime[j+1:] == S:
                    result_indices.append(i + 1)
                    break

        # Check for deletion (S should be one character longer than T')
        elif len_S == len_T_prime + 1:
            for j in range(len_S):
                if S[:j] + S[j+1:] == T_prime:
                    result_indices.append(i + 1)
                    break

        # Check for modification (S and T' should be of the same length)
        elif len_S == len_T_prime:
            diff_count = sum(1 for a, b in zip(S, T_prime) if a != b)
            if diff_count == 1:
                result_indices.append(i + 1)

    # Output the result
    print(len(result_indices))
    if result_indices:
        print(" ".join(map(str, result_indices)))

