def can_fill_grid(N, R, C):
    # Initialize the grid with empty cells
    grid = [['.' for _ in range(N)] for _ in range(N)]

    # Fill the first column with R and the first row with C
    for i in range(N):
        grid[i][0] = R[i]  # Fill the first column with R
        grid[0][i] = C[i]  # Fill the first row with C

    # Function to check if we can place a character in the grid
    def can_place(grid, row, col, char):
        for k in range(N):
            if grid[row][k] == char or grid[k][col] == char:
                return False
        return True

    # Backtracking to fill the grid
    def fill_grid(grid, row, col):
        if row == N:  # If we filled all rows, return True
            return True
        if col == N:  # Move to the next row
            return fill_grid(grid, row + 1, 0)
        if grid[row][col] != '.':  # If the cell is already filled, move to the next column
            return fill_grid(grid, row, col + 1)

        for char in 'ABC':
            if can_place(grid, row, col, char):  # Check if we can place the character
                grid[row][col] = char
                if fill_grid(grid, row, col + 1):  # Recur to fill the next cell
                    return True
                grid[row][col] = '.'  # Backtrack
        return False

    # Start filling the grid
    if not fill_grid(grid, 0, 0):
        return False, None

    # Check if the grid is valid
    for i in range(N):
        if sorted([cell for cell in grid[i] if cell != '.']) != ['A', 'B', 'C']:
            return False, None
    for j in range(N):
        if sorted([grid[i][j] for i in range(N) if grid[i][j] != '.']) != ['A', 'B', 'C']:
            return False, None

    return True, grid

