from itertools import combinations

def find_minimum_spanning_tree_cost(N, M, K, edges):
    # Function to check if a set of edges forms a spanning tree
    def is_spanning_tree(selected_edges):
        parent = list(range(N + 1))  # Union-Find structure

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            rootX = find(x)
            rootY = find(y)
            if rootX != rootY:
                parent[rootY] = rootX

        for u, v, _ in selected_edges:
            union(u, v)

        # Check if all vertices are connected
        root = find(1)
        for i in range(2, N + 1):
            if find(i) != root:
                return False
        return True

    min_cost = float('inf')

    # Generate all combinations of N-1 edges
    for selected_edges in combinations(edges, N - 1):
        if is_spanning_tree(selected_edges):
            total_weight = sum(weight for _, _, weight in selected_edges)
            cost = total_weight % K
            min_cost = min(min_cost, cost)

    return min_cost

