def count_repeated_substrings(N, S):
    unique_substrings = set()
    consecutive_count = 1

    for i in range(1, N):
        if S[i] == S[i - 1]:
            consecutive_count += 1
        else:
            for length in range(1, consecutive_count + 1):
                unique_substrings.add(S[i - 1] * length)
            consecutive_count = 1  # Reset for the new character

    for length in range(1, consecutive_count + 1):
        unique_substrings.add(S[N - 1] * length)

    return len(unique_substrings)

