import math

def find_min_difference(D):
    min_diff = float('inf')
    max_val = int(math.isqrt(D)) + 1  # We can go up to sqrt(D)

    for x in range(max_val):
        y_squared = D - x * x
        if y_squared < 0:
            continue
        y = int(math.isqrt(y_squared))
        for candidate_y in (y, y - 1):
            if candidate_y >= 0:
                S = x * x + candidate_y * candidate_y
                diff = abs(S - D)
                if diff < min_diff:
                    min_diff = diff

    return min_diff

