def place_dragon_parts(N):
    # Initialize the grid
    grid = [[None] * N for _ in range(N)]

    # Center position for Takahashi
    center = N // 2
    grid[center][center] = 'T'  # Place Takahashi at the center

    # Directions for adjacent cells (up, down, left, right)
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    # Function to check if a position is valid
    def is_valid(x, y):
        return 0 <= x < N and 0 <= y < N and grid[x][y] is None

    # Recursive function to place parts
    def place_parts(x, last_x, last_y):
        if x > N * N - 1:
            return True  # All parts placed successfully
        for dx, dy in directions:
            new_x, new_y = last_x + dx, last_y + dy
            if is_valid(new_x, new_y):
                grid[new_x][new_y] = str(x)
                if place_parts(x + 1, new_x, new_y):
                    return True
                grid[new_x][new_y] = None  # Backtrack
        return False

    # Start from one of the adjacent cells of Takahashi
    start_positions = [(center - 1, center), (center + 1, center), (center, center - 1), (center, center + 1)]

    for start_x, start_y in start_positions:
        if is_valid(start_x, start_y):
            grid[start_x][start_y] = '1'
            if place_parts(2, start_x, start_y):
                break
            grid[start_x][start_y] = None  # Backtrack if needed

    return grid

