def most_frequent_character(S):
    # Step 1: Count character frequencies
    frequency = {}
    for char in S:
        if char in frequency:
            frequency[char] += 1
        else:
            frequency[char] = 1

    # Step 2: Identify the character with the maximum frequency
    max_freq = 0
    result_char = ''

    for char in frequency:
        if frequency[char] > max_freq:
            max_freq = frequency[char]
            result_char = char
        elif frequency[char] == max_freq:
            if char < result_char:  # Compare alphabetically
                result_char = char

    # Step 3: Output the result
    print(result_char)

