def solve():
    import sys
    input = sys.stdin.read
    from sys import maxsize

    data = input().splitlines()
    N, M = map(int, data[0].split())

    # Initialize the graph with infinity
    graph = [[maxsize] * N for _ in range(N)]

    # Read edges and populate the graph
    for i in range(M):
        U, V, W = map(int, data[i + 1].split())
        graph[U - 1][V - 1] = min(graph[U - 1][V - 1], W)  # Handle multiple edges by taking the minimum weight

    # Floyd-Warshall algorithm to find shortest paths between all pairs
    for k in range(N):
        for i in range(N):
            for j in range(N):
                if graph[i][j] > graph[i][k] + graph[k][j]:
                    graph[i][j] = graph[i][k] + graph[k][j]

    # Check if all vertices are reachable from the first vertex
    def is_reachable_from(start):
        visited = [False] * N
        stack = [start]
        while stack:
            node = stack.pop()
            if not visited[node]:
                visited[node] = True
                for neighbor in range(N):
                    if graph[node][neighbor] < maxsize and not visited[neighbor]:
                        stack.append(neighbor)
        return all(visited)

    if not is_reachable_from(0):
        print("No")
        return

    # Dynamic Programming to solve the TSP-like problem
    full_mask = (1 << N) - 1
    dp = [[maxsize] * N for _ in range(1 << N)]

    # Initialize DP for single vertex visits
    for i in range(N):
        dp[1 << i][i] = 0

    # Fill the DP table
    for mask in range(1 << N):
        for i in range(N):
            if (mask & (1 << i)) == 0:
                continue
            for j in range(N):
                if (mask & (1 << j)) != 0:
                    continue
                new_mask = mask | (1 << j)
                if graph[i][j] < maxsize:  # Ensure there's a valid edge
                    dp[new_mask][j] = min(dp[new_mask][j], dp[mask][i] + graph[i][j])

    # Find the minimum cost to visit all vertices
    min_cost = min(dp[full_mask][i] for i in range(N) if dp[full_mask][i] < maxsize)

    if min_cost == maxsize:
        print("No")
    else:
        print(min_cost)

