def total_cost(N):
    # Dictionary to store the computed costs for memoization
    memo = {}

    def compute_cost(x):
        if x < 2:
            return 0
        if x in memo:
            return memo[x]

        # Calculate the cost for the current x
        cost = x + compute_cost(x // 2) + compute_cost((x + 1) // 2)
        memo[x] = cost
        return cost

    return compute_cost(N)

