def generate_alternating_string(N):
    result = []
    for i in range(N + (N + 1)):  # Total length is N + (N + 1) = 2N + 1
        if i % 2 == 0:
            result.append('1')  # Append '1' at even indices
        else:
            result.append('0')  # Append '0' at odd indices
    return ''.join(result)

