import sys
import math

def count_valid_integers(x, n, m, lcm_nm):
    return (x // n) + (x // m) - 2 * (x // lcm_nm)

def lcm(a, b):
    return a * (b // math.gcd(a, b))

def find_kth_smallest(n, m, k):
    lcm_nm = lcm(n, m)

    # Binary search for the K-th valid integer
    low, high = 1, 2 * k * max(n, m)

    while low < high:
        mid = (low + high) // 2
        if count_valid_integers(mid, n, m, lcm_nm) < k:
            low = mid + 1
        else:
            high = mid

    return low

def main():
    input_data = sys.stdin.read().strip()
    n, m, k = map(int, input_data.split())

    result = find_kth_smallest(n, m, k)
    print(result)

if __name__ == "__main__":
    main()

class SegmentTree:
    def __init__(self, n):
        self.n = n
        self.tree = [0] * (4 * n)
        self.lazy = [0] * (4 * n)

    def _apply(self, node, start, end):
        # Apply the lazy flip to the current node
        self.tree[node] = (end - start + 1) - self.tree[node]  # Flip the count of good segments
        if start != end:  # Not a leaf node
            self.lazy[node] ^= 1  # Mark as needing a flip

    def _push(self, node, start, end):
        if self.lazy[node]:
            self._apply(node, start, end)
            mid = (start + end) // 2
            self._apply(2 * node + 1, start, mid)
            self._apply(2 * node + 2, mid + 1, end)
            self.lazy[node] = 0

    def update(self, l, r, node=0, start=0, end=None):
        if end is None:
            end = self.n - 1
        self._push(node, start, end)
        if start > r or end < l:
            return
        if start >= l and end <= r:
            self._apply(node, start, end)
            return
        mid = (start + end) // 2
        self.update(l, r, 2 * node + 1, start, mid)
        self.update(l, r, 2 * node + 2, mid + 1, end)
        self.tree[node] = self.tree[2 * node + 1] + self.tree[2 * node + 2]

    def query(self, l, r, node=0, start=0, end=None):
        if end is None:
            end = self.n - 1
        self._push(node, start, end)
        if start > r or end < l:
            return 0
        if start >= l and end <= r:
            return self.tree[node]
        mid = (start + end) // 2
        left_query = self.query(l, r, 2 * node + 1, start, mid)
        right_query = self.query(l, r, 2 * node + 2, mid + 1, end)
        return left_query + right_query

def is_good_string(s):
    for i in range(len(s) - 1):
        if s[i] == s[i + 1]:
            return False
    return True

