def main():
    data = input().splitlines()
    n, q = map(int, data[0].split())
    s = list(data[1].strip())

    seg_tree = SegmentTree(n)
    for i in range(n):
        seg_tree.tree[i + n] = 1 if i == 0 or s[i] != s[i - 1] else 0
    for i in range(n - 1, 0, -1):
        seg_tree.tree[i] = seg_tree.tree[2 * i] + seg_tree.tree[2 * i + 1]

    results = []
    for i in range(2, 2 + q):
        query = list(map(int, data[i].split()))
        if query[0] == 1:
            l, r = query[1] - 1, query[2] - 1
            seg_tree.update(l, r)
            for j in range(l, r + 1):
                s[j] = '1' if s[j] == '0' else '0'
        elif query[0] == 2:
            l, r = query[1] - 1, query[2] - 1
            extracted = s[l:r + 1]
            if is_good_string(extracted):
                results.append("Yes")
            else:
                results.append("No")

