def prime_sieve(max_n):
    """ Returns the smallest prime factor for each number up to max_n. """
    spf = list(range(max_n + 1))  # Smallest Prime Factor
    for i in range(2, int(max_n**0.5) + 1):
        if spf[i] == i:  # i is prime
            for j in range(i * i, max_n + 1, i):
                if spf[j] == j:
                    spf[j] = i
    return spf

def get_parity_signature(x, spf):
    """ Returns the parity signature of the number x based on its prime factorization. """
    if x == 0:
        return (0,)  # Special case for zero
    parity = {}
    while x > 1:
        prime = spf[x]
        if prime in parity:
            parity[prime] += 1
        else:
            parity[prime] = 1
        x //= prime
    # Convert to a tuple of (prime, parity) where parity is 0 or 1
    return tuple((p, cnt % 2) for p, cnt in parity.items() if cnt % 2)

def count_square_pairs(N, A):
    max_value = 200000
    spf = prime_sieve(max_value)

    parity_count = {}
    total_pairs = 0

    for number in A:
        signature = get_parity_signature(number, spf)

        # Count pairs with the same signature
        if signature in parity_count:
            total_pairs += parity_count[signature]
            parity_count[signature] += 1
        else:
            parity_count[signature] = 1

        # Special case for zero
        if number == 0:
            total_pairs += len(A) - 1  # All pairs with zero

    return total_pairs

